const body = $('Webhook').item.json.body ?? {};
const args = body;
const aiEngineUrl = body.aiEngineUrl ?? 'http://ai-engine:8000';
const recipientHint = args.recipientHint ?? '';
const purpose = args.purpose ?? '';
const toneHint = args.toneHint ?? '丁寧';

const systemPrompt = `あなたは営業部のメール下書きAIです。\n以下のJSONのみで返してください (前後の説明文・コードフェンス禁止):\n{\"subject\":\"...\",\"body\":\"... (改行は\\\\nで表現)\"}`;
const userPrompt = `宛先ヒント: ${recipientHint}\n目的: ${purpose}\nトーン: ${toneHint}\n上記でメール下書きを作成してください。`;

return [{ json: { aiEngineUrl, payload: { messages: [{ role:'system', content: systemPrompt }, { role:'user', content: userPrompt }], department:'SALES', org_id: body.orgId ?? 'unknown', plan: body.plan ?? 'STARTER', json_mode: true } } }];

const raw = $json.content ?? '';
let parsed = { subject: '', body: raw };
try { parsed = JSON.parse(raw); } catch (e) { parsed = { subject: '(JSONパース失敗)', body: raw }; }
return [{ json: { status: 'success', error_type: null, message: 'メール下書きを生成しました', data: { taskType: 'email_draft', subject: parsed.subject, body: parsed.body, _ai_meta: { model: $json.model, tokens_used: $json.tokens_used } } } }];
